#!/usr/bin/perl

use CGI qw(param);
use strict;
use warnings;

my $log_dir = '/path/to/log/directory';

my $filename = param('logfile');
open(FH, "$log_dir/$filename") or die "Can't open file: $!";

print "Content-type: text/plain\n\n";
while (my $line = <FH>) {
    print $line;
}

close(FH);
